    yd = 0.2 + 0.1*sin(2*t);
    zd = 0.543;
elseif t >= 20 && t <= 25
    xd = 0.597;
    yd = -0.513;
    zd = -0.275;
end
Xd = [xd; yd; zd];

% 5. Velocidades de posición deseada
if t >= 10 && t < 20
    dxd = -0.1*sin(2*t)*2;
    dyd = 0.1*cos(2*t)*2;
    dzd = 0;
else
    dxd = 0;
    dyd = 0;
    dzd = 0;
end
dXd = [dxd; dyd; dzd];


% 6. Ganancias de control
kx = 1;
ky = 1;
kz = 1;

K =  [kx 0  0
      0  ky 0
      0  0  kz];

% 7. Definir la ecuación de control cinemático
dq = J_inv * (dXd - K * (X - Xd));
end
